query ListSavedSearches($type: String, $limit: Int, $offset: Int) {
  savedSearches {
    listSavedSearches(type: $type, limit: $limit, offset: $offset) {
      searches {
        id
        name
        description
        type
        search_term
        filters
        sort_field
        sort_direction
        page_size
        created_at
        updated_at
        last_used_at
        use_count
      }
      total
    }
  }
}

