mutation CreateSearch {
  savedSearches {
    createSavedSearch(input: {
      name: "Tech Companies"
      type: "company"
      search_term: "technology"
      filters: { industry: "Technology" }
      page_size: 50
    }) {
      id
      name
      type
      created_at
    }
  }
}

mutation UseSearch {
  savedSearches {
    updateSavedSearchUsage(id: "1")
  }
}

query ListSearches {
  savedSearches {
    listSavedSearches(limit: 10) {
      searches {
        id
        name
        type
        last_used_at
        use_count
      }
      total
    }
  }
}

mutation UpdateSearch {
  savedSearches {
    updateSavedSearch(id: "1", input: {
      name: "Updated Tech Companies"
      page_size: 100
    }) {
      id
      name
      page_size
      updated_at
    }
  }
}
